const header = $input.first().json.headers['x-forwarded-for'] ?? '';
const rawIp = header.split(',')[0].trim();
const cleanIp = rawIp.replace(/[.:]/g, '_');

// Datum im Format YYYY-MM-DD (UTC)
const date = new Date().toISOString().slice(0, 10);

// Fertige Firestore-Doc-IDs
const ipUsageId = `${cleanIp}_${date}`;
const dailyUsageId = date;

return [{ json: { rawIp, cleanIp, date, ipUsageId, dailyUsageId } }];

const body = $('recipe-webhook').first().json.body;

const UNITS = ['gram', 'ml', 'liter', 'piece'];
const COOKING_TIMES = ['quick', 'medium', 'complex'];
const CUISINES = ['german', 'italian', 'japanese', 'indian', 'gourmet', 'fusion'];
const DIETS = ['vegetarian', 'vegan', 'keto', 'none'];

const errors = [];

// ingredients
if (!Array.isArray(body.ingredients) || body.ingredients.length === 0) {
  errors.push('ingredients must have at least one entry');
} else {
  body.ingredients.forEach((ing, i) => {
    if (!ing.name || typeof ing.name !== 'string') errors.push(`ingredients[${i}]: name missing`);
    if (!ing.amount || ing.amount <= 0) errors.push(`ingredients[${i}]: amount must be > 0`);
    if (!UNITS.includes(ing.unit)) errors.push(`ingredients[${i}]: unit invalid`);
  });
}

// portions
if (!Number.isInteger(body.portions) || body.portions < 1 || body.portions > 12) {
  errors.push('portions must be an integer between 1 and 12');
}

// cooks
if (!Number.isInteger(body.cooks) || body.cooks < 1 || body.cooks > 3) {
  errors.push('cooks must be an integer between 1 and 3');
}

// cookingTime, cuisine, diet
if (!COOKING_TIMES.includes(body.cookingTime)) errors.push('cookingTime invalid');
if (!CUISINES.includes(body.cuisine)) errors.push('cuisine invalid');
if (!DIETS.includes(body.diet)) errors.push('diet invalid');

// Ergebnis
if (errors.length > 0) {
  return [{ json: { valid: false, errors } }];
}

return [{ json: { valid: true, body } }];

// Beide Zähler lesen, fehlend = 0
const ipItem = $('ipUsage lesen').first().json;
const dailyItem = $('dailyUsage lesen').first().json;

const ipCount = ipItem.count ?? 0;
const dailyCount = dailyItem.count ?? 0;

const IP_LIMIT = 3;
const DAILY_LIMIT = 12;

let blocked = false;
let reason = '';

if (dailyCount >= DAILY_LIMIT) {
  blocked = true;
  reason = 'daily_limit';
} else if (ipCount >= IP_LIMIT) {
  blocked = true;
  reason = 'ip_limit';
}

return [{ json: { blocked, reason, ipCount, dailyCount } }];

const body = $('recipe-webhook').first().json.body;

// Nutzer-Eingaben lesbar für den Prompt aufbereiten
const ingredientList = body.ingredients
  .map(i => `${i.amount} ${i.unit} ${i.name}`)
  .join(', ');

// System-/Instruktions-Text
const promptText = `You are a professional recipe creator. Generate EXACTLY 3 distinct recipes.

USER INPUT:
- Available ingredients: ${ingredientList}
- Portions: ${body.portions}
- Number of cooks: ${body.cooks}
- Cooking time preference: ${body.cookingTime}
- Cuisine: ${body.cuisine}
- Diet: ${body.diet}

HARD RULES:
1. Each recipe MUST use at least 70% of the user's available ingredients (in "yourIngredients").
2. Each recipe may add AT MOST 3 extra ingredients (in "extraIngredients").
3. Respect the diet "${body.diet}" strictly. If "none", no restriction.
4. Respect the cuisine "${body.cuisine}".
5. Nutrition values are PER SINGLE PORTION, not total.
6. Distribute cooking steps across ${body.cooks} cook(s) using the "chef" field (1 to ${body.cooks}). If there is only 1 cook, every step has chef = 1.
7. Check quantity plausibility: amounts must realistically serve ${body.portions} portion(s).
8. All units must be one of: gram, ml, liter, piece.
9. Steps must be numbered starting at 1 and be in logical order.

Return ONLY structured JSON matching the provided schema.`;

// responseSchema für Gemini (Vertrag 2, ohne id/likes/createdAt — die setzt n8n später)
const responseSchema = {
  type: "object",
  properties: {
    recipes: {
      type: "array",
      items: {
        type: "object",
        properties: {
          title: { type: "string" },
          cuisine: { type: "string" },
          tags: { type: "array", items: { type: "string" } },
          cookingTimeMinutes: { type: "integer" },
          portions: { type: "integer" },
          cooks: { type: "integer" },
          nutritionPerPortion: {
            type: "object",
            properties: {
              calories: { type: "integer" },
              protein: { type: "integer" },
              fat: { type: "integer" },
              carbs: { type: "integer" }
            },
            required: ["calories", "protein", "fat", "carbs"]
          },
          yourIngredients: {
            type: "array",
            items: {
              type: "object",
              properties: {
                name: { type: "string" },
                amount: { type: "number" },
                unit: { type: "string" }
              },
              required: ["name", "amount", "unit"]
            }
          },
          extraIngredients: {
            type: "array",
            items: {
              type: "object",
              properties: {
                name: { type: "string" },
                amount: { type: "number" },
                unit: { type: "string" }
              },
              required: ["name", "amount", "unit"]
            }
          },
          directions: {
            type: "array",
            items: {
              type: "object",
              properties: {
                step: { type: "integer" },
                title: { type: "string" },
                chef: { type: "integer" },
                instruction: { type: "string" }
              },
              required: ["step", "title", "chef", "instruction"]
            }
          }
        },
        required: ["title", "cuisine", "tags", "cookingTimeMinutes", "portions", "cooks", "nutritionPerPortion", "yourIngredients", "extraIngredients", "directions"]
      }
    }
  },
  required: ["recipes"]
};

return [{ json: { promptText, responseSchema } }];

