const response = $('Gemini aufrufen').first().json;

// 1. Den Text-Teil herausholen
let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Gemini response has unexpected structure (no candidates/parts)');
}

// 2. String zu echtem Objekt parsen
let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error('Gemini did not return valid JSON: ' + e.message);
}

// 3. Struktur prüfen: genau 3 Rezepte
if (!Array.isArray(parsed.recipes)) {
  throw new Error('Gemini response missing "recipes" array');
}
if (parsed.recipes.length !== 3) {
  throw new Error(`Expected exactly 3 recipes, got ${parsed.recipes.length}`);
}

// 4. Pro Rezept: max. 3 extraIngredients (Vertrag-Regel)
parsed.recipes.forEach((r, i) => {
  if (!Array.isArray(r.extraIngredients)) {
    throw new Error(`Recipe ${i}: extraIngredients missing`);
  }
  if (r.extraIngredients.length > 3) {
    throw new Error(`Recipe ${i}: too many extraIngredients (${r.extraIngredients.length})`);
  }
});

// Alles ok → die 3 Rezepte als einzelne Items weitergeben
return parsed.recipes.map(recipe => ({ json: recipe }));

const now = new Date().toISOString();

return $input.all().map(item => ({
  json: {
    ...item.json,
    createdAt: now
  }
}));

const allItems = $input.all();

const recipeIds = allItems.map(item => {
  return item.json.id ?? item.json.name.split('/').pop();
});

return [{ json: { recipeIds } }];

